CREATE TABLE IF NOT EXISTS checks (
    check_id INT AUTO_INCREMENT PRIMARY KEY,
    check_name VARCHAR(255),
    check_type VARCHAR(255),
    check_category VARCHAR(255),
    category_sort_id INT,
    check_sort_id INT,
    check_status INT,
    check_price INT,
    check_block INT,
    check_configuration JSON,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);
ALTER TABLE checks ADD CONSTRAINT temp_unique_check UNIQUE (check_name);


ALTER TABLE checks DROP INDEX temp_unique_check;
